<span class="line">  <span class="token keyword">static</span> <span class="token keyword">final</span> _instance <span class="token operator">=</span> <span class="token class-name">CounterService</span><span class="token punctuation">.</span><span class="token function">_</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
