<span class="line"><span class="token function">print</span><span class="token punctuation">(</span><span class="token class-name">CounterService</span><span class="token punctuation">.</span>instance<span class="token punctuation">.</span>currentCount<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// prints 0</span></span>
